import play.api.mvc._
import java.io.File

class FileController extends Controller {

  private val allowedBaseDir = new File("uploads")

  def serveFile(filename: String) = Action {
    val resolvedPath = resolvePath(filename)
    if (resolvedPath != null && resolvedPath.exists() && resolvedPath.isFile) {
      Ok.sendFile(resolvedPath)
    } else {
      NotFound
    }
  }

  private def resolvePath(filename: String): File = {
    val baseDir = allowedBaseDir.getCanonicalFile
    val filePath = new File(baseDir, filename).getCanonicalFile

    if (filePath.getParentFile.getAbsolutePath == baseDir.getAbsolutePath) {
      filePath
    } else {
      null
    }
  }

}